1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill single live cell (underpopulation)", () => {
9	    const liveCells = [[0, 0]];
10	    expect(nextGeneration(liveCells)).toEqual([]);
11	  });
12	  it("should keep live cell with two neighbors (survival)", () => {
13	    const liveCells = [[1, 1], [0, 0], [0, 1]];
14	    expect(nextGeneration(liveCells)).toEqual([[1, 1]]);
15	  });
16	  it("should keep live cell with three neighbors (survival)", () => {
17	    const liveCells = [[1, 1], [1, 2], [0, 1], [2, 1]];
18	    expect(nextGeneration(liveCells)).toEqual([[1, 1]]);
19	  });
20	  it("should kill live cell with four neighbors (overpopulation)", () => {
21	    const liveCells = [[1, 1], [0, 1], [1, 0], [2, 1], [1, 2]];
22	    expect(nextGeneration(liveCells)).toEqual([]);
23	  });
24	  it("should revive dead cell with exactly three neighbors (reproduction)", () => {
25	    const liveCells = [[0, 0], [0, 1], [0, 2]];
26	    expect(nextGeneration(liveCells)).toEqual([[1, 1]]);
27	  });
28	  it("should handle blinker pattern (period 2)", () => {
29	    // Vertical blinker
30	    const verticalBlinker = [[0, 0], [1, 0], [2, 0]];
31	    const nextGen = nextGeneration(verticalBlinker);
32	    // Should become horizontal: three cells in a row turn to three cells in a column
33	    expect(nextGen).toEqual([[1, -1], [1, 0], [1, 1]]);
34	  });
35	  it("should handle block pattern (stable)", () => {
36	    // Block pattern: 2x2 stable configuration
37	    const blockPattern = [[0, 0], [0, 1], [1, 0], [1, 1]];
38	    expect(nextGeneration(blockPattern)).toEqual(blockPattern);
39	  });
40	  it.todo("should handle multiple independent patterns");
41	  it.todo("should support negative coordinates");
42	});
