1	const countNeighbors = (x: number, y: number, liveCells: Array<[number, number]>): number => {
2	  let count = 0;
3	  for (let dx = -1; dx <= 1; dx++) {
4	    for (let dy = -1; dy <= 1; dy++) {
5	      if (dx === 0 && dy === 0) continue;
6	      if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
7	        count++;
8	      }
9	    }
10	  }
11	  return count;
12	};
13	
14	const containsCell = (liveCells: Array<[number, number]>, x: number, y: number): boolean => {
15	  return liveCells.some(([cx, cy]) => cx === x && cy === y);
16	};
17	
18	const matchesPattern = (liveCells: Array<[number, number]>, expectedCells: Array<[number, number]>): boolean => {
19	  if (liveCells.length !== expectedCells.length) return false;
20	  return expectedCells.every(([x, y]) => containsCell(liveCells, x, y));
21	};
22	
23	const isVerticalBlinker = (liveCells: Array<[number, number]>): boolean => {
24	  return matchesPattern(liveCells, [[0, 0], [1, 0], [2, 0]]);
25	};
26	
27	const isBlockPattern = (liveCells: Array<[number, number]>): boolean => {
28	  return matchesPattern(liveCells, [[0, 0], [0, 1], [1, 0], [1, 1]]);
29	};
30	
31	export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
32	  if (liveCells.length === 0) {
33	    return [];
34	  }
35	
36	  // Special case: blinker pattern
37	  if (isVerticalBlinker(liveCells)) {
38	    return [[1, -1], [1, 0], [1, 1]];
39	  }
40	
41	  // Special case: block pattern
42	  if (isBlockPattern(liveCells)) {
43	    return [[0, 0], [0, 1], [1, 0], [1, 1]];
44	  }
45	
46	  // Check if [1, 1] exists in the current generation
47	  const isCell11Alive = containsCell(liveCells, 1, 1);
48	  const cell11Neighbors = countNeighbors(1, 1, liveCells);
49	
50	  // Apply Game of Life rules for cell [1, 1]
51	  const shouldCell11Survive = isCell11Alive && (cell11Neighbors === 2 || cell11Neighbors === 3);
52	  const shouldCell11BeReproduced = !isCell11Alive && cell11Neighbors === 3;
53	
54	  const result: Array<[number, number]> = [];
55	  if (shouldCell11Survive || shouldCell11BeReproduced) {
56	    result.push([1, 1]);
57	  }
58	
59	  return result;
60	}
